    26→/**
    27→ * PDF文档列表Activity
    28→ * 显示从网页发现的PDF文档，用户可以逐个下载
    29→ */
    30→class PdfListActivity : AppCompatActivity() {
    31→    private lateinit var webView: WebView
    32→    private val TAG = "CourtAssistant"
    33→    private val scope = lifecycleScope
    34→    private var smsId: Long = 0
    35→    private var sourceUrl: String = ""
    36→    private val db by lazy { (application as App).db }
    37→
    38→    // PDF文档列表
    39→    private val pdfList = mutableListOf<PdfItem>()
    40→    private var processedCount = 0
    41→
    42→    data class PdfItem(
    43→        val url: String,
    44→        val name: String,
    45→        var downloaded: Boolean = false,
    46→        var filePath: String = "",
    47→        var docId: Long = 0
    48→    )
    49→
    50→    private val client = OkHttpClient.Builder()
    51→        .followRedirects(true)
    52→        .connectTimeout(30, TimeUnit.SECONDS)
    53→        .readTimeout(60, TimeUnit.SECONDS)
    54→        .build()
    55→
    56→    @SuppressLint("SetJavaScriptEnabled")
    57→    override fun onCreate(savedInstanceState: Bundle?) {
    58→        super.onCreate(savedInstanceState)
    59→        setContentView(R.layout.activity_pdf_list)
    60→
    61→        webView = findViewById<WebView>(R.id.webView)
    62→        smsId = intent.getLongExtra("smsId", 0)
    63→        sourceUrl = intent.getStringExtra("url") ?: ""
    64→
    65→        Log.d(TAG, "PdfListActivity: smsId=$smsId url=$sourceUrl")
    66→
    67→        setupWebView()
    68→        loadPage()
    69→    }
