    71→    private fun setupWebView() {
    72→        webView.settings.apply {
    73→            javaScriptEnabled = true
    74→            domStorageEnabled = true
    75→            allowFileAccess = true
    76→            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
    77→            userAgentString = "Mozilla/5.0 (Linux; Android 12) AppleWebKit/537.36 Chrome/120.0 Mobile Safari/537.36"
    78→        }
    79→
    80→        webView.addJavascriptInterface(PdfJsBridge(), "PdfBridge")
    81→
    82→        // 拦截PDF下载
    83→        webView.setDownloadListener { downloadUrl, _, _, _, _ ->
    84→            Log.d(TAG, "PDF download detected: $downloadUrl")
    85→            handlePdfDownload(downloadUrl)
    86→        }
    87→
    88→        webView.webViewClient = object : WebViewClient() {
    89→            override fun shouldOverrideUrlLoading(view: WebView, request: WebResourceRequest): Boolean {
    90→                val url = request.url.toString()
    91→                // 检测PDF URL
    92→                if (url.contains(".pdf", ignoreCase = true) ||
    93→                    url.contains("pdf", ignoreCase = true) && url.contains("download")) {
    94→                    Log.d(TAG, "PDF URL detected: $url")
    95→                    handlePdfDownload(url)
    96→                    return true
    97→                }
    98→                return false
    99→            }
   100→
   101→            override fun onPageFinished(view: WebView, url: String) {
   102→                Log.d(TAG, "Page loaded: $url")
   103→
   104→                // 页面加载完成后，延迟扫描PDF
   105→                view.postDelayed({
   106→                    scanForPdfs(view)
   107→                }, 2000)
   108→
   109→                // 多次扫描以捕获动态加载的PDF
   110→                view.postDelayed({
   111→                    scanForPdfs(view)
   112→                }, 5000)
   113→
   114→                view.postDelayed({
   115→                    scanForPdfs(view)
   116→                }, 10000)
   117→
   118→                view.postDelayed({
   119→                    finishScanning()
   120→                }, 15000)
   121→            }
   122→        }
   123→
   124→        webView.loadUrl(sourceUrl)
   125→    }
   126→
   127→    private fun loadPage() {
   128→        Log.d(TAG, "Loading page: $sourceUrl")
   129→        webView.loadUrl(sourceUrl)
   130→
   131→        // 超时处理
   132→        scope.launch {
   133→            delay(60000)
   134→            if (!isFinishing) {
   135→                Log.d(TAG, "Page load timeout, finishing scan")
   136→                finishScanning()
   137→            }
   138→        }
   139→    }
