   141→    private fun scanForPdfs(view: WebView) {
   142→        val js = """
   143→            (function() {
   144→                var results = [];
   145→
   146→                // 法院文档关键词
   147→                var keywords = ['传票', '通知书', '举证', '受理', '判决', '裁定',
   148→                                '送达', '应诉', '起诉', '答辩', '告知', '决定',
   149→                                '文书', '下载', '查看', '打印'];
   150→
   151→                // 多种选择器组合
   152→                var selectors = [
   153→                    'a[href]',
   154→                    'a[onclick]',
   155→                    '[class*="file"]',
   156→                    '[class*="doc"]',
   157→                    '[class*="document"]',
   158→                    '[class*="item"]',
   159→                    '[class*="card"]',
   160→                    '[onclick]'
   161→                ];
   162→
   163→                for (var s = 0; s < selectors.length; s++) {
   164→                    var elements = document.querySelectorAll(selectors[s]);
   165→                    for (var i = 0; i < elements.length; i++) {
   166→                        var el = elements[i];
   167→                        var href = el.href || el.getAttribute('data-href') ||
   168→                                      el.getAttribute('onclick') || '';
   169→                        var text = (el.innerText || el.textContent || '').trim();
   170→                        var className = el.className || '';
   171→                        var lowerHref = href.toLowerCase();
   172→                        var lowerText = text.toLowerCase();
   173→                        var lowerClass = className.toLowerCase();
   174→
   175→                        // 检查是否是PDF
   176→                        var isPdf = lowerHref.indexOf('.pdf') >= 0 ||
   177→                                       lowerHref.indexOf('pdf') >= 0 ||
   178→                                       lowerText.indexOf('.pdf') >= 0 ||
   179→                                       lowerText.indexOf('PDF') >= 0;
   180→
   181→                        // 检查是否包含文档关键词
   182→                        var hasKeyword = keywords.some(function(kw) {
   183→                            return lowerText.indexOf(kw) >= 0 || lowerClass.indexOf(kw) >= 0;
   184→                        });
   185→
   186→                        // 检查是否是文件项
   187→                        var isFileItem = lowerClass.indexOf('file') >= 0 ||
   188→                                       lowerClass.indexOf('doc') >= 0 ||
   189→                                       lowerClass.indexOf('item') >= 0 ||
   190→                                       lowerClass.indexOf('card') >= 0;
   191→
   192→                        if ((isPdf || hasKeyword || isFileItem) &&
   193→                            href && href !== '#' && href !== 'javascript:;') {
   194→                            results.push({
   195→                                url: href,
   196→                                name: text || '文档'
   197→                            });
   198→                        }
   199→                    }
   200→                }
   201→
   202→                // 去重
   203→                var unique = [];
   204→                var seen = new Set();
   205→                for (var j = 0; j < results.length; j++) {
   206→                    if (!seen.has(results[j].url)) {
   207→                        seen.add(results[j].url);
   208→                        unique.push(results[j]);
   209→                    }
   210→                }
   211→
   212→                return unique;
   213→            })()
   214→        """.trimIndent()
   215→
   216→        view.evaluateJavascript(js) { result ->
   217→            try {
   218→                val json = result?.trim()?.removeSurrounding("\"")
   219→                    ?.replace("\\\"", "\"")?.replace("\\\\", "\\")
   220→                if (json.isNullOrBlank() || json == "null" || json == "[]") return@evaluateJavascript
   221→
   222→                Log.d(TAG, "Scan result: $json")
   223→
   224→                // 解析JSON
   225→                val items = parsePdfList(json)
   226→                val newCount = items.size
   227→
   228→                Log.d(TAG, "Found $newCount PDFs")
   229→                updatePdfList(items)
   230→            } catch (e: Exception) {
   231→                Log.e(TAG, "Parse error", e)
   232→            }
   233→        }
   234→    }
   235→
   236→    private fun parsePdfList(json: String): List<PdfItem> {
   237→        val items = mutableListOf<PdfItem>()
   238→        try {
   239→            val jsonArray = org.json.JSONArray(json)
   240→            for (i in 0 until jsonArray.length()) {
   241→                val obj = jsonArray.getJSONObject(i)
   242→                val url = obj.getString("url")
   243→                val name = obj.getString("name")
   244→
   245→                // 检查是否在当前列表中已下载
   246→                val existing = pdfList.find { it.url == url }
   247→                val item = PdfItem(
   248→                    url = url,
   249→                    name = name,
   250→                    downloaded = existing?.downloaded ?: false,
   251→                    filePath = existing?.filePath ?: "",
   252→                    docId = existing?.docId ?: 0
   253→                )
   254→                items.add(item)
   255→            }
   256→        } catch (e: Exception) {
   257→            Log.e(TAG, "JSON parse error", e)
   258→        }
   259→        return items
   260→    }
   261→
   262→    private fun updatePdfList(items: List<PdfItem>) {
   263→        pdfList.clear()
   264→        pdfList.addAll(items)
   265→        processedCount = items.count { it.downloaded }
   266→
   267→        // 通知JavaScript更新UI
   268→        webView.evaluateJavascript("""
   269→            (function() {
   270→                if (window.PdfBridge && window.PdfBridge.updatePdfList) {
   271→                    window.PdfBridge.updatePdfList(${org.json.JSONArray(items.map {
   272→                        mapOf("url" to it.url, "name" to it.name,
   273→                               "downloaded" to it.downloaded) })});
   274→                }
   275→            })()
   276→        """.trimIndent(), null)
   277→    }
   278→
   279→    private fun handlePdfDownload(url: String) {
   280→        scope.launch(Dispatchers.IO) {
   281→            // 检查是否已处理
   282→            if (pdfList.any { it.url == url && it.downloaded }) {
   283→                Log.d(TAG, "Already downloaded: $url")
   284→                return@launch
   285→            }
   286→
   287→            // 下载PDF
   288→            try {
   289→                val guessName = android.webkit.URLUtil.guessFileName(url, "", "application/pdf")
   290→                val file = File(filesDir, "pdfs/${System.currentTimeMillis()}_$guessName")
   291→                file.parentFile?.mkdirs()
   292→
   293→                val request = Request.Builder().url(url).build()
   294→                val response = client.newCall(request).execute()
   295→
   296→                if (!response.isSuccessful) {
   297→                    Log.e(TAG, "Download failed: HTTP ${response.code}")
   298→                    withContext(Dispatchers.Main) {
   299→                        Toast.makeText(this@PdfListActivity, "下载失败", Toast.LENGTH_SHORT).show()
   300→                    }
   301→                    return@launch
   302→                }
   303→
   304→                response.body?.byteStream()?.use { input ->
   305→                    file.outputStream().use { output -> input.copyTo(output) }
   306→                }
   307→
   308→                if (file.length() == 0L) {
   309→                    file.delete()
   310→                    Log.e(TAG, "Downloaded file is empty")
   311→                    return@launch
   312→                }
   313→
   314→                Log.d(TAG, "Downloaded: ${file.name} (${file.length()} bytes)")
   315→
   316→                // 保存到数据库
   317→                val item = pdfList.find { it.url == url }
   318→                if (item != null) {
   319→                    item.downloaded = true
   320→                    item.filePath = file.absolutePath
   321→
   322→                    val docId = db.documentDao().insert(
   323→                        DocumentRecord(
   324→                            smsId = smsId,
   325→                            fileName = guessName,
   326→                            filePath = file.absolutePath,
   327→                            fileSize = file.length(),
   328→                            sourceUrl = url,
   329→                            downloadTime = System.currentTimeMillis(),
   330→                            displayName = item.name
   331→                        )
   332→                    )
   333→
   334→                    item.docId = docId
   335→
   336→                    // 解析传票信息
   337→                    PdfParser.parseAndSync(this@PdfListActivity, db, docId)
   338→                }
   339→
   340→                // 更新UI
   341→                withContext(Dispatchers.Main) {
   342→                    updatePdfList(pdfList)
   343→                    Toast.makeText(this@PdfListActivity, "已下载: ${file.name}", Toast.LENGTH_SHORT).show()
   344→                }
   345→
   346→            } catch (e: Exception) {
   347→                Log.e(TAG, "Download error", e)
   348→                withContext(Dispatchers.Main) {
   349→                    Toast.makeText(this@PdfListActivity, "下载失败: ${e.message}", Toast.LENGTH_SHORT).show()
   350→                }
   351→            }
   352→        }
   353→    }
   354→
   355→    private fun finishScanning() {
   356→        Log.d(TAG, "Scanning finished, total PDFs: ${pdfList.size}")
   357→        // 等待一段时间后自动关闭
   358→        scope.launch {
   359→            delay(5000)
   360→            if (!isFinishing) {
   361→                finish()
   362→            }
   363→        }
   364→    }
   365→
   366→    inner class PdfJsBridge {
   367→        @JavascriptInterface
   368→        fun updatePdfList(json: String) {
   369→            // JavaScript可以调用这个方法更新列表
   370→            Log.d(TAG, "updatePdfList called: $json")
   371→        }
   372→
   373→        @JavascriptInterface
   374→        fun downloadPdf(url: String, name: String) {
   375→            Log.d(TAG, "Manual download request: $url - $name")
   376→            handlePdfDownload(url)
   377→        }
   378→    }
   379→
   380→    override fun onDestroy() {
   381→        super.onDestroy()
   382→        webView.destroy()
   383→    }
   384→}
