   119→                override fun onReceivedError(view: WebView?, request: WebResourceRequest?, error: WebResourceError?) {
   120→                    Log.e(TAG, "WebView error: ${error?.description}")
   121→                    if (autoMode) {
   122→                        tvScanningStatus.text = "加载失败，正在重试..."
