   128→                override fun shouldInterceptRequest(view: WebView?, request: WebResourceRequest?): WebResourceResponse? {
   129→                    val reqUrl = request?.url?.toString() ?: ""
   130→                    val method = request?.method ?: "GET"
   131→
   132→                    // 拦截PDF下载请求（包括API调用）
   133→                    if (reqUrl.contains(".pdf", ignoreCase = true) ||
   134→                        reqUrl.contains("download", ignoreCase = true) ||
   135→                        reqUrl.contains("file", ignoreCase = true) ||
   136→                        reqUrl.contains("doc", ignoreCase = true)) {
   137→
   138→                        Log.d(TAG, "Intercepted potential PDF request: $reqUrl, method=$method")
   139→
   140→                        // 对于GET请求且包含.pdf的，直接下载
   141→                        if (method == "GET" && reqUrl.contains(".pdf", ignoreCase = true)) {
   142→                            handler.post {
   143→                                handlePdfDownload(reqUrl)
   144→                            }
   145→                            // 返回空响应阻止WebView处理
   146→                            return WebResourceResponse("application/pdf", "UTF-8", null)
   147→                        }
   148→                    }
   149→                    return super.shouldInterceptRequest(view, request)
   150→                }
