   153→            webChromeClient = object : WebChromeClient() {
   154→                override fun onProgressChanged(view: WebView?, newProgress: Int) {
   155→                    super.onProgressChanged(view, newProgress)
   156→                    if (autoMode) {
   157→                        when {
   158→                            newProgress < 30 -> tvScanningStatus.text = "正在连接服务器..."
   159→                            newProgress < 60 -> tvScanningStatus.text = "正在加载页面内容..."
   160→                            newProgress < 90 -> tvScanningStatus.text = "正在加载文档列表..."
   161→                            newProgress == 100 -> tvScanningStatus.text = "页面加载完成，正在扫描文档..."
   162→                        }
   163→                    }
