   166→                override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
   167→                    consoleMessage?.let {
   168→                        val msg = it.message()
   169→                        Log.d(TAG, "Console: $msg")
   170→
   171→                        // 监听console.log中的PDF URL
   172→                        if (msg.contains(".pdf", ignoreCase = true) ||
   173→                            msg.contains("download", ignoreCase = true)) {
   174→                            handler.post {
   175→                                try {
   176→                                    // 尝试从console消息中提取URL
   177→                                    val urlPattern = Regex("""(https?://[^\s"']+\.(?:pdf|PDF)[^\s"']*)""")
   178→                                    val match = urlPattern.find(msg)
   179→                                    match?.let { m ->
   180→                                        val pdfUrl = m.groupValues[1]
   181→                                        handlePdfDownload(pdfUrl)
   182→                                    }
   183→                                } catch (e: Exception) {
   184→                                    Log.e(TAG, "Error parsing console message", e)
   185→                                }
   186→                            }
   187→                        }
   188→                    }
   189→                    return true
   190→                }
   191→            }
