   561→    /**
   562→     * 实际下载PDF文件
   563→     */
   564→    private suspend fun downloadPdfFile(url: String): File? {
   565→        val client = okhttp3.OkHttpClient.Builder()
   566→            .followRedirects(true)
   567→            .connectTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
   568→            .readTimeout(60, java.util.concurrent.TimeUnit.SECONDS)
   569→            .build()
   570→
   571→        val request = okhttp3.Request.Builder()
   572→            .url(url)
   573→            .addHeader("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")
   574→            .addHeader("Referer", this@WebViewActivity.url)
   575→            .build()
   576→
   577→        val response = try {
   578→            client.newCall(request).execute()
   579→        } catch (e: Exception) {
   580→            Log.e(TAG, "HTTP request failed", e)
   581→            return null
   582→        }
   583→
   584→        if (!response.isSuccessful) {
   585→            Log.e(TAG, "HTTP ${response.code} for $url")
   586→            return null
   587→        }
   588→
   589→        val contentType = response.header("Content-Type", "") ?: ""
   590→        Log.d(TAG, "Content-Type: $contentType")
   591→
   592→        return try {
   593→            val dir = File(filesDir, "pdfs").also { it.mkdirs() }
   594→            val fileName = extractFileNameFromUrl(url)
   595→            val file = File(dir, "${System.currentTimeMillis()}_$fileName")
   596→
   597→            response.body?.byteStream()?.use { input ->
   598→                file.outputStream().use { output -> input.copyTo(output) }
   599→            }
   600→
   601→            if (file.length() > 0) {
   602→                Log.d(TAG, "Downloaded ${file.length()} bytes")
   603→                file
   604→            } else {
   605→                file.delete()
   606→                null
   607→            }
   608→        } catch (e: Exception) {
   609→            Log.e(TAG, "Download file save failed", e)
   610→            null
   611→        }
   612→    }
