    45→            try {
    46→                val count = withContext(Dispatchers.IO) {
    47→                    val latestTime = db.smsDao().getLatestTime() ?: 0
    48→                    Log.d(TAG, "syncSms: latestTime=$latestTime")
    49→                    val records = SmsReader.readAll(getApplication<App>().contentResolver, latestTime)
    50→                    Log.d(TAG, "syncSms: found ${records.size} records from 12368")
    51→                    var c = 0
